whisper:
: repeat {
  _ 0 = ?? drop drop ""
  | _ 1 - ` over ` repeat strcat ]
} ;
"abc" 3 repeat .

: dist {
  _ over - _ *      // (y2-y1)^2
  swap over - _ *   // (x2-x1)^2
  + fsqrt            // sqrt(sum)
} ;
0 0 3 4 dist .

: prime {
  _ 2 < ?? drop #f ]
  _ 2 = ?? drop #t ]
  _ 2 % 0 = ?? drop #f ]
  3 { _ _ * over >= } { _ over % 0 = ?? drop drop #f | 2 + ] } #
  #t
} ;
17 prime .
